    let mut state = WorkerState::new(config);
    state.speed_score = 92.0;
    state.reserve_slots(8);

    let info = WorkerStatusInfo::from(&state);

    assert_eq!(info.id, "gpu-worker");
    assert_eq!(info.used_slots, 8);
    assert_eq!(info.total_slots, 16);
    assert_eq!(info.speed_score, 92.0);
    assert_eq!(info.status, "healthy");
}

#[test]
