    let config = WorkerConfig {
        id: WorkerId::new("flaky-worker"),
        host: "flaky.example.com".to_string(),
        user: "builder".to_string(),
        identity_file: "~/.ssh/id_rsa".to_string(),
        total_slots: 8,
        priority: 50,
        tags: vec![],
