#[tokio::test]
async fn test_status_endpoint_returns_valid_json() {
    let daemon = TestDaemon::start().await;

    let mut stream = UnixStream::connect(&daemon.socket_path).unwrap();
    stream.set_read_timeout(Some(Duration::from_secs(5))).unwrap();

    // Send HTTP-like request
    let request = "GET /status HTTP/1.1\r\nHost: localhost\r\n\r\n";
    stream.write_all(request.as_bytes()).unwrap();

    let mut response = String::new();
    stream.read_to_string(&mut response).unwrap();

    // Parse JSON body (skip HTTP headers)
    let body_start = response.find("\r\n\r\n").unwrap() + 4;
    let body = &response[body_start..];

    let json: serde_json::Value = serde_json::from_str(body)
        .expect("Response should be valid JSON");

